# Helper functions for file handling

def read_pipe_delimited_file(filename, fieldnames):
    data = []
    filepath = os.path.join(DATA_DIR, filename)
    if not os.path.exists(filepath):
        return data
    with open(filepath, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) < len(fieldnames):
                continue
            entry = {}
            for idx, field in enumerate(fieldnames):
                entry[field] = parts[idx]
            data.append(entry)
    return data


def write_pipe_delimited_file(filename, data, fieldnames):
    filepath = os.path.join(DATA_DIR, filename)
    with open(filepath, 'w', encoding='utf-8') as f:
        for entry in data:
            line = '|'.join(str(entry.get(field, '')).strip() for field in fieldnames)
            f.write(line + '\n')


