    return render_template('checkout.htm', cart_items=display_cart_items, total_amount=total_amount)


# Route /order/<order_id>
@app.route('/order/<order_id>', methods=['POST'])
def orderDetail(order_id):
    orders = read_pipe_delimited_file('orders.txt', ORDERS_FIELDS)
    order = None
    for o in orders:
        if o['order_id'] == order_id:
            order = {k: v for k, v in o.items() if k != 'status'}
            break
    if not order:
        return redirect(url_for('home'))

    order_items_all = read_pipe_delimited_file('order_items.txt', ORDER_ITEMS_FIELDS)
    order_items = {}
    for oi in order_items_all:
        if oi['order_id'] == order_id:
            order_items[oi['order_item_id']] = {
                'book_id': oi['book_id'],
                'title': '',
                'quantity': oi['quantity'],
                'price': oi['price']
            }

    # Populate title from books
    books = {b['book_id']: b for b in read_pipe_delimited_file('books.txt', BOOKS_FIELDS)}
    for oi_id, oi_data in order_items.items():
        book = books.get(oi_data['book_id'])
        if book:
            oi_data['title'] = book['title']

    return render_template('order_detail.html', order=order, order_items=order_items)


