# Route /write_review GET and POST
@app.route('/write_review', methods=['GET', 'POST'])
def writeReview():
    if request.method == 'GET':
        # List purchased books (all books)
        purchased_books = []
        books = read_pipe_delimited_file('books.txt', BOOKS_FIELDS)
        for book in books:
            purchased_books.append({
                'bookID': book['book_id'],
                'title': book['title']
            })

        return render_template('write_review.htm', purchased_books=purchased_books)

    # POST method to submit review
    book_id = request.form.get('bookID')
    customer_name = request.form.get('customer_name', 'Anonymous')
    rating = request.form.get('rating')
    review_text = request.form.get('review_text', '')
    review_date = datetime.now().strftime('%Y-%m-%d')

    if not book_id or not rating or not review_text:
        return redirect(url_for('home'))

    # Load reviews
    reviews = read_pipe_delimited_file('reviews.txt', REVIEWS_FIELDS)
    last_review_id = max([int(r['review_id']) for r in reviews], default=0)
    new_review_id = last_review_id + 1

    new_review = {
        'review_id': str(new_review_id),
        'book_id': book_id,
        'customer_name': customer_name,
        'rating': rating,
        'review_text': review_text,
        'review_date': review_date
    }

    reviews.append(new_review)
    write_pipe_delimited_file('reviews.txt', reviews, REVIEWS_FIELDS)

    return redirect(url_for('home'))


